import type * as Brevo from "../../../../index.js";
/**
 * @example
 *     {
 *         pid: "pid",
 *         balanceDefinitionId: "balanceDefinitionId"
 *     }
 */
export interface GetContactBalancesRequest {
    /** Loyalty Program Id */
    pid: string;
    /** Include balances tied to internal definitions. */
    includeInternal?: boolean;
    /** Limit the number of records returned */
    limit?: number;
    /** Skip a number of records */
    offset?: number;
    /** Sort order */
    sort?: Brevo.GetContactBalancesRequestSort;
    /** Field to sort by */
    sortField?: Brevo.GetContactBalancesRequestSortField;
    /** Balance Definition ID (required) */
    balanceDefinitionId: string;
}
